163:     /// passes wired by value, not by call) are invisible as edges. Returns the
164:     /// referenced symbol so the core emits a `References` edge.
165:     fn extract_value_reference(&self, node: SyntaxNode<'_>, source: &str) -> Option<String> {
166:         if node.kind() != "let_declaration" {
167:             return None;
168:         }
169:         let value = get_child_by_field(node, "value")?;
170:         if !matches!(value.kind(), "identifier" | "scoped_identifier") {
171:             return None;
